import waitForReady from "./ready.js";

var cloakedTabs = {};

/**
 * I think CLOAK is not used anywhere
 * Consider this laterrrrrrrrrrrrrrrr
 */
export async function cloakTab(tabHandle, createElementFunc) {
  var tabCloakData = {
    active: true,
    func: createElementFunc,
  };
  cloakedTabs[tabHandle] = tabCloakData;
  onTabUpdatedForCloak(tabHandle);
  chrome.tabs.onUpdated.addListener(onTabUpdatedForCloak);
}

function injectedAddCloak(createElementFunc) {
  var cloakElement = document.getElementById("XBROWSER_CLOAK_OVERLAY_ELEMENT");
  if (!cloakElement) {
    cloakElement = createElementFunc();
    cloakElement.id = "XBROWSER_CLOAK_OVERLAY_ELEMENT";
    (document.body || document.documentElement).appendChild(cloakElement);
  }
}

async function onTabUpdatedForCloak(updatedTabId) {
  var tabCloakData = cloakedTabs[updatedTabId];
  if (!!tabCloakData) {
    if (tabCloakData.active) {
      await chrome.scripting.executeScript({
        target: { tabId: updatedTabId },
        func: injectedAddCloak,
        args: tabCloakData.func,
        injectImmediately: true,
      });
    } else {
      if (tabCloakData.uncloakCallback) {
        tabCloakData.uncloakCallback("tab updated");
        delete tabCloakData.uncloakCallback;
      }
    }
  }
}

function injectedRemoveCloak() {
  var cloakElement = document.getElementById("XBROWSER_CLOAK_OVERLAY_ELEMENT");
  if (!!cloakElement) {
    cloakElement.parentNode.removeChild(cloakElement);
  }
}

export async function uncloakTab(tabHandle) {
  var tabCloakData = cloakedTabs[tabHandle];
  if (!tabCloakData) {
    return;
  }

  tabCloakData.active = false;
  tabCloakData.uncloakCallback = callback;
  var uncloaked = false;

  async function doUncloakTab(reason) {
    if (!!uncloaked) {
      return;
    }
    uncloaked = true;

    if (cloakedTabs[tabHandle] !== tabCloakData) {
      return;
    }

    if (typeof tabCloakData.uncloakCallback === "function") {
      tabCloakData.uncloakCallback(reason);
      delete tabCloakData.uncloakCallback;
    }
    delete cloakedTabs[tabHandle];

    await chrome.scripting.executeScript({
      target: { tabId: updatedTabId },
      func: injectedRemoveCloak,
      injectImmediately: true,
    });
  }

  setTimeout(function () {
    doUncloakTab("timeout");
  }, 5000);

  waitForReady(tabHandle).then(() => {
    doUncloakTab("ready state");
  });
}
