/*
  Execute login step in background context of the extension. Uses eval (in separaete module) to evaluate step code.
 */

import loginDefs from "../utils/loginDefs.js";
import clientLoginBackgroundExecutor from "./backgroundCodeExecutorEval.js";
import oneloginTabs from "../../global/tabs/oneloginTabs.js";
import { getCookies } from "../../global/storage/cookies.js";
import createApiFunctions from "../utils/createApiFunctions.js";
import { getBrowserCapabilities } from "../../global/capabilities.js";

var premadBackgroundSteps = [
  {
    name: "Set report level",
    context: "Background",
    code: function (api) {
      var userContext = api.getUserContext();
      userContext.reportLevel = "normal";
    },
  },
  {
    name: "Uncloak",
    context: "Background",
    code: function (api) {
      api.uncloak();
    },
  },
  {
    name: "Stop if WWW authentication performed",
    context: "Background",
    code: function (api) {
      if (api.wasWWWAuthenticationPerformed && api.wasWWWAuthenticationPerformed()) {
        api.log("WWW Authentication performed, stopping");
        return api.SUCCESS;
      }
      return api.NEXT;
    },
  },
];

class BackgroundExecutor {
  constructor() {}

  getContext() {
    return loginDefs.stepContext.BACKGROUND;
  }

  async executeStep(loginProc) {
    var tabHandle = loginProc.getTabHandle();
    var apiDataIn = loginProc.getApiContext();
    const tabInfo = await oneloginTabs.getTabInfo(tabHandle);
    apiDataIn.about.capabilities = getBrowserCapabilities();
    apiDataIn.location = tabInfo.url;

    try {
      const cookies = await getCookies();
      apiDataIn.cookies = cookies;
    } catch (error) {
      loginProc.logError("Cannot read cookies: "+ err);
      apiDataIn.cookies = [];
    }
    if (!!self.bgLog) {
      self.bgLog(
        "Processing BG-step '"+ loginProc.getCurrentStep().name + "' ... will mostlikely fail."
      );
    }

    let step = loginProc.getCurrentStep();
    /**
     * Update the code here using predefined background functions
     */
    // let code = step.code;
    let stepCode = premadBackgroundSteps.find((_step) => _step.name === step.name);
    if (!stepCode) {
      //Check this later
      // callback(undefined, {});
      return;
    }
    return this.executeCode(stepCode.code, apiDataIn);
  }

  /**
   * Runs the given code in the 'background' context of the extension.
   * @param code - string containing the function to run, e.g. 'function(api) { return api.NEXT; }'
   * @param apiDataIn - input data for all the API functions
   * @param callback - function(err, apiDataOut)
   */
  executeCode(code, apiDataIn) {
    if (!!self.bgLog) {
      self.bgLog("execute code: "+ code);
    }
    var apiDataOut = {};
    apiDataOut.userContext = apiDataIn.userContext;

    var api = {
      NEXT: loginDefs.apiResult.NEXT,
      WAIT: loginDefs.apiResult.WAIT,
      SUCCESS: loginDefs.apiResult.SUCCESS,
      FAILURE: loginDefs.apiResult.FAILURE,
    };

    createApiFunctions(api, apiDataIn, apiDataOut);

    try {
      apiDataOut.result = clientLoginBackgroundExecutor(code, api);
    } catch (err) {
      if (!!self.bgLog) {
        self.bgLog("try-catch error code: "+ err.code + "message: "+ err.message);
        self.bgLog("edge (ignore BG script errors) - set hardcoded report level= normal");
      }

      apiDataOut.error = (err && err.message) || "unknown error";
    }

    if (!!self.bgLog) {
      self.bgLog("execute code apiDataOut: "+ JSON.stringify(apiDataOut));
    }
    if (!!apiDataOut.error) {
      // return callback(apiDataOut.error, apiDataOut);
      return apiDataOut;
    }
    // return callback(undefined, apiDataOut);
    return apiDataOut;
  }
}

export default BackgroundExecutor;
