/**
 * Decorates the api object with the api functions. The functions work just with the data objects.
 * @param api
 * @param apiDataIn
 * @param apiDataOut
 */

function createApiFunctions(api, apiDataIn, apiDataOut) {
  function pushAction(type, param) {
    apiDataOut.actions = apiDataOut.actions || [];
    apiDataOut.actions.push({
      type: type,
      param: param,
    });
  }

  // just a wrapping function to be able to mock "location.hostname"in tests
  api._getWindowHostname = function () {
    return window.location.hostname;
  };

  function checkDomainEnforcement() {
    var matchedConnectorIds = apiDataIn.variables.matchedConnectorIds;
    if (!Array.isArray(matchedConnectorIds) || matchedConnectorIds.length === 0) {
      // no matched connectors IDs -> don't test URLs
      return;
    }

    function getHostname(url) {
      var match = url.match(/:\/\/(.[^/:]+)/i);
      if (
        match != null &&
        match.length > 1 &&
        typeof match[1] === "string"&&
        match[1].length > 0
      ) {
        return match[1];
      } else {
        return null;
      }
    }

    function secondLevelDomain(hostname) {
      return hostname.split(".").splice(-2).join(".");
    }

    var loginUrlDomain = secondLevelDomain(getHostname(apiDataIn.variables.loginUrl));
    var locationDomain = secondLevelDomain(api._getWindowHostname());
    if (locationDomain !== loginUrlDomain) {
      api.log(
        "Domain Enforcement - Different domain used to fill credentials by possible matching connectors:"+
          JSON.stringify(matchedConnectorIds) +
          "start-domain='"+
          loginUrlDomain +
          "' credential-domain='"+
          locationDomain +
          "'"
      );
    }
  }

  api.getUserContext = function () {
    return apiDataIn.userContext;
  };

  api.getTotalTime = function () {
    return apiDataIn.totalTime;
  };

  api.getStepTime = function () {
    return apiDataIn.stepTime;
  };

  api.getIdleTime = function () {
    return apiDataIn.idleTime;
  };

  api.getUsername = function () {
    return apiDataIn.variables.username;
  };

  api.getPassword = function () {
    checkDomainEnforcement();
    return apiDataIn.variables.password;
  };

  api.getNewPassword = function () {
    return apiDataIn.variables.newPassword;
  };

  api.getLoginUrl = function () {
    return apiDataIn.variables.loginUrl;
  };

  api.getBasicAuthUrl = function () {
    return apiDataIn.variables.basicAuthUrl;
  };

  api.getCapabilities = function () {
    return apiDataIn.about.capabilities;
  };

  api.getAdditionalFields = function () {
    return apiDataIn.variables.additionalFields;
  };

  api.getLocation = function () {
    return apiDataIn.location;
  };

  api.setLocation = function (newLocation, authParams) {
    var param;
    if (typeof newLocation === "string") {
      param = {
        url: newLocation,
      };
      if (typeof authParams === "object") {
        param.username = authParams.username;
        param.password = authParams.password;
      }
      pushAction("setLocation", param);
    } else {
      pushAction("log", "Illegal parameter to setLocation");
    }
  };

  api.wasWWWAuthenticationPerformed = function () {
    return apiDataIn.wasWWWAuthenticationPerformed;
  };

  api.log = function () {
    if (arguments.length === 0) {
      return;
    }
    function toString(item) {
      var prop, parts;

      if (typeof item === "string") {
        return item;
      }

      try {
        return JSON.stringify(item);
      } catch (_err) {
        parts = [];
        if (item.nodeType) {
          return item.outerHTML;
        } else if (Array.isArray(item)) {
          for (prop = 0; prop < item.length; prop++) {
            parts.push(toString(item[prop]));
          }
          return "["+ parts.join(",") + "]";
        }
        if (typeof item === "object") {
          for (var prop2 in item) {
            // jslint false-positives if prop is used here
            parts.push(prop2);
            parts.push(":");
            parts.push(toString(item[prop2]));
          }
          return "{"+ parts.join(",") + "}";
        } else {
          return "$@#&";
        }
      }
    }

    var message = [];
    Array.prototype.slice.call(arguments).forEach(function (item) {
      message.push(toString(item));
    });
    message = message.join("");

    if (!apiDataIn.variables || !apiDataIn.variables.test) {
      //do not trim in test environment
      if (message.length > 1000) {
        message = message.substring(0, 997) + "...[trimmed]";
      }
    }
    pushAction("log", message);
  };

  api.getCookie = function (domain, name) {
    if (!apiDataIn.cookies) {
      return undefined;
    }

    for (var i = 0; i < apiDataIn.cookies.length; ++i) {
      var c = apiDataIn.cookies[i];
      if (!!c.name && typeof c.name === "string"&& c.name.match(name)) {
        if (!domain || (c.domain && typeof c.domain === "string"&& c.domain.match(domain))) {
          return c;
        }
      }
    }
    return undefined;
  };

  api.getAllCookies = function () {
    return apiDataIn.cookies;
  };

  api.clearCookie = function (domain, name) {
    if (name instanceof RegExp) {
      pushAction("clearCookie", {
        domain: domain,
        regExp: name.toString(),
      });
    } else {
      pushAction("clearCookie", {
        domain: domain,
        name: name,
      });
    }
  };

  api.waitForReady = function () {
    pushAction("waitForReady");
  };

  api.about = function () {
    return apiDataIn.about;
  };

  api.isMinimumVersion = function (major, minor) {
    if (!apiDataIn.about || !apiDataIn.about.version) {
      return false;
    }
    if (apiDataIn.version.major > major) {
      return true;
    }
    if (apiDataIn.version.major < major) {
      return false;
    }
    return apiDataIn.version.minor >= minor;
  };

  api.cloak = function () {
    pushAction("cloak");
  };

  api.uncloak = function () {
    pushAction("uncloak");
  };
}

export default createApiFunctions;
