import { OneloginApiServer } from "../global/oneloginApiServer/oneloginApiServer.js";
import { handleMessage } from "./messageHandler.js";
import subdomainUrl from "../global/storage/subdomainUrl.js";
import oneloginTabs from "../global/tabs/oneloginTabs.js";
import UserNavigationTracker from "../global/tabs/userNavigationTracker.js";
import portalPageClassifier from "../global/oneloginApiServer/portalPageClassifier.js";
import CurrentUser from "../currentUser/currentUser.js";
import ActionHandler from "./actionHandler.js";
import { initFormServiceRedirectWebHandler } from "./formServiceRedirectWebHandler.js";
import Workflow from "../login/initLoginWorkflow.js";
import inMemoryCache from "../global/storage/cache.js";
import { VERSION } from "../const.js";
import { OneloginAirbrake } from "../global/airbrake.js";
import config from "../../config.json";

var oneloginApiServer;
var userNavigationTracker;
var currentUser;
var actionHandler;
var workflow;

/**
 * Callback is necessary here since this function is called by content script
 * using background message and the messaging/resonse handling b/w content script and
 * background service happens via callback
 */
const getOnMessage = () => {
  return function onMessage(event, sender, sendResponse) {
    var callbackCalled = false;
    console.log("message received: ", event);
    var isAsyncResponse = handleMessage(
      {
        event: event,
        eventName: event.type,
        eventParams: event.params,
        tabHandler: sender.tab && sender.tab.id,
        callback: function (err, responseParams) {
          callbackCalled = true;
          try {
            sendResponse({
              status: err ? "ERROR": "SUCCESS",
              data: err ? err : responseParams,
            });
          } catch (err) {
            console.error("can't dispatch message to page", event.type, responseParams, err);
          }
        },
      },
      oneloginApiServer,
      actionHandler,
      workflow,
      currentUser
    );

    if (!isAsyncResponse && !callbackCalled) {
      // synchronous callback not called -> call it to prevent from:
      // "Unchecked runtime.lastError: The message port closed before a response was received."logged in console
      sendResponse({}); // or sendResponse({}) ?
    }
    return isAsyncResponse;
  };
};

function initEssentials() {
  // If the objects are already initialised then return\\\\\\\\\\\\\\\\\\
  if (oneloginApiServer && userNavigationTracker && currentUser && actionHandler) return;
  /**
   * Initilise the objects
   */
  console.log("initEssentials");
  oneloginApiServer = new OneloginApiServer();
  userNavigationTracker = new UserNavigationTracker(portalPageClassifier);
  currentUser = new CurrentUser(oneloginApiServer);
  actionHandler = new ActionHandler({
    oneloginApiServer,
    currentUser,
    subdomainUrl,
    oneloginTabs,
  });
  workflow = Workflow(oneloginApiServer);
  /**
   * Init Airbrake
   */
  new OneloginAirbrake().init(config.airbrake);
}

async function init() {
  initEssentials();
  console.log("initialised essentials");
  /**
   * Register message handler
   */
  chrome.runtime.onMessage.addListener(getOnMessage());

  userNavigationTracker.initWebHandlers();

  //only legacy portal is handled by these navigations; new portal is handled by actionHandler above
  userNavigationTracker.on("userNavigated.portalLoginPage", (url) => {
    console.log("userNavigated.portalLoginPage: ", url);
    actionHandler.handleAction({ type: "userLogout", url });
  });
  userNavigationTracker.on("userNavigated.portalMainPage", (url) => {
    console.log("userNavigated.portalMainPage: ", url);
    actionHandler.handleAction({ type: "userInitialized", url });
  });
  userNavigationTracker.on("userNavigated.portalUserSettings", () => {
    console.log("userNavigated.portalUserSettings: ", url);
    actionHandler.handleAction({ type: "reinitUser"});
  });
  oneloginApiServer.on("oneloginApiServer.login", function () {
    console.log("oneloginApiServer.login");
    inMemoryCache.invalidateCache();
    actionHandler.handleAction({ type: "reinitUser"});
  });

  /**
   * NOTE: unified way of logging out from old and new portal.
   * It has a consequence where new portal logout process is started twice now
   * (due to 1) `logoutUser` action from new portal
   * and 2) navigation to login screen which automatically evokes logout too.
   * It has no side effect, as there are mechanisms to stop the process when user is already logged out.
   * It will be narrowed in future with removal of old-portal support
   */
  oneloginApiServer.on("oneloginApiServer.logout", function () {
    console.log("oneloginApiServer.logout");
    inMemoryCache.invalidateCache();
    actionHandler.handleAction({ type: "logoutUser"});
  });

  /**
   * Update the versioning later
   */
  await initFormServiceRedirectWebHandler(`chrome_${VERSION}`);

  const portalUrl = await subdomainUrl.get();

  const portalTab = await oneloginTabs.getLastTab();

  // if (!!portalTab) {
  //     console.log("reloading")
  //     await oneloginTabs.reload(portalTab); //this reinits server
  // } else if (portalUrl !== null) {
  //     console.log("server init")
  //     oneloginApiServer.init(portalUrl);
  // }

  /**
   * Reverted the if conditions from the previous version of the extension
   * to fix the rerendering of web-portal issue
   * Revert the changes in case of any issue noticed.
   */
  if (portalUrl !== null) {
    console.log("oneloginApiServer.init: ", portalUrl);
    oneloginApiServer.init(portalUrl);
  } else if (!!portalTab) {
    console.log("oneloginTabs.reload: ", portalTab);
    await oneloginTabs.reload(portalTab); //this reinits server
  }
}

/**
 * Re consider this init function once.
 * Check this thoroughly
 */

init()
  .then(() => {
    console.log(`Onelogin Extension version ${VERSION} initialized on ${new Date()}`);
  })
  .catch((err) => {
    console.error("Error initialising service worker: ", err);
    /**
     * Reconsider this exit
     */
    // process.exit()
  });

/**
 * Don't remove the below setInterval.
 * It is done to keep background service worker active.
 * Since service workers after every 30 seconds go to sleep if not used actively
 * and on click of new tab or any specific events chrome wakes up the service worker which results
 * in an excessive number of api hits to our form-service for no reason.
 *
 */
setInterval(() => {
  // console.log(`heartbeat`)
  let date = new Date().getTime();
  chrome.storage.local
    .set({ lastHeartbeat: date })
    .then(() => console.log("heartbeat"))
    .catch(console.error);
}, 20000); // Every 20 seconds
/**
 * END
 */
