import { VERSION } from "../const.js";
import { clearExtTimeout, setExtTimeout } from "./timeout.js";

const controller = new AbortController();
const signal = controller.signal;

function getErrorNameByStatusCode(statusCode) {
  const errorNames = {
    400: "BadRequest",
    401: "Unauthorized",
    403: "Forbidden",
    404: "NotFound",
    405: "MethodNotAllowed",
    408: "RequestTimeout",
    500: "InternalServerError",
    502: "BadGateway",
    503: "ServiceUnavailable",
    504: "GatewayTimeout",
  };

  return errorNames[statusCode] || "UnknownError";
}

async function parseResponse(response, params) {
  let parsedResponse;

  if (params.json) {
    try {
      parsedResponse = await response.json();
      if (response.status >= 400 && response.status <= 599) {
        const err = new Error(
          `xbrowser: fetch error: ${
            response.statusText || parsedResponse.message || "Internal server error"
          }`
        );
        err.status = response.status;
        err.name = getErrorNameByStatusCode(response.status);
        throw err;
      }
    } catch (ex) {
      throw ex;
    }
  } else if (params.xml) {
    try {
      const xmlString = await response.text();
      const parser = new DOMParser();
      parsedResponse = parser.parseFromString(xmlString, "text/xml");
    } catch (ex) {
      throw ex;
    }
  } else {
    parsedResponse = await response.text();
  }
  return parsedResponse;
}

async function send(params) {
  const { contentType, method, url, body, json } = params;
  const options = {
    method: method || "GET",
    signal,
    headers: new Headers({
      ...(params.headers || {}),
      ...(contentType ? { "Content-Type": contentType } : {}),
      ...(json ? { "Content-Type": "application/json;charset=UTF-8"} : {}),
    }),
  };

  if (body) options.body = json ? JSON.stringify(body) : body;

  // const requestTimeout = setExtTimeout(() => {
  //   controller.abort();
  //   throw new Error("request: fetch timeout");
  // }, params.requestTimeout || 30000);

  /**
   * Custom query params to identify extension api calls
   */
  const updatedUrl = new URL(url);
  updatedUrl.searchParams.set("plugin_version", VERSION);
  /**
   *
   */

  const response = await fetch(updatedUrl.toString(), options);
  // clearExtTimeout(requestTimeout);

  if (response.ok) {
    const parsedResponse = await parseResponse(response, params);
    return parsedResponse;
  } else {
    const err = new Error("request: fetch error: "+ response.statusText);
    err.status = response.status;
    try {
      await parseResponse(response, { json: true });
    } catch (errDetails) {
      err.name = errDetails.name;
      err.message = err.message + ": "+ errDetails.message;
      err.serverMessage = errDetails.message;
      if (errDetails.details) {
        err.details = errDetails.details;
      }
      throw err;
    }
    throw err;
  }
}

export default {
  parseResponse,
  send,
};
