/*
 The login workflow and redirection is different for current/old onelogin extension (v2) and this/new one (v3).
 In order to give OneLogin server chance to decide, the extension alters all sign-in calls that are handled by the server by inserting its version and platform.
 The monorail server then decide whether to forward the request to the new form-service (for extension v3).
 Please not, that we need to alter also calls that were not made by the extension itself, but also when user manually enters the signin url into the browser.

 There are currently following urls that may trigger signin process in portal:
      /client/apps/select/{id}
      /start/{id}
      /launch/{id}

 Example:
      https://onelogininc.onelogin.com/start/12345 -> https://onelogininc.onelogin.com/start/12345?plugin_version=chrome_3.0.19
*/

// const isOneloginPortal = require("../shared/oneloginServer/portalPageClassifier")
//     .isOneloginPortal,

import portalPageClassifier from "../global/oneloginApiServer/portalPageClassifier.js";
import utils from "./utils.js";

const pluginVersionParam = "plugin_version";

function addExtensionStringOnPortalUrl(url, extensionVersionString) {
  if (portalPageClassifier.isOneloginPortal(url)) {
    console.log("formServiceRedirectWebHandler intercepted request: ", url);
    if (!utils.isParamInUrl(url, pluginVersionParam)) {
      const redirectUrl = utils.addParamToUrl(url, pluginVersionParam, extensionVersionString);
      console.log("redirecting to :", redirectUrl);
      return {
        redirectUrl,
      };
    }
  }
}

