/**
 * This runs the code in background using eval(). Defined standalone to minimize accessible variables.
 * @param stepCode
 * @param api
 * @returns what the code returns
 */
var clientLoginBackgroundExecutor = function (stepCode, api) {
  /* jshint -W061 */
  // var compiledCode = (new (this[(function() { return 'Function'; })()])('return (' + stepCode + ')'))();
  var compiledCode = stepCode;
  if (!compiledCode || typeof compiledCode !== "function") {
    throw new Error("Step code does not evaluate to a function.");
  }
  return compiledCode(api);
};

export default clientLoginBackgroundExecutor;
