/*
  Hold data and context of steps phase - each loginSteps can have more phases (login, test). This object offers common methods.
 */

import loginDefs from "../utils/loginDefs.js";
import CurrentTime from "../utils/currentTime.js";

class StepsPhase {
  constructor(phaseName, steps) {
    this.currentTime = new CurrentTime();
    this.phaseName = phaseName;
    // this.steps = this.generateSteps();
    this.steps = steps;
    this.currentStep = 0;
  }

  getName() {
    return this.phaseName;
  }

  getCurrentStep() {
    if (!this.steps || this.steps.length <= this.currentStep) {
      return this.normalizeStep(null);
    }
    return this.normalizeStep(this.steps[this.currentStep]);
  }

  getCurrentStepIndex() {
    return this.currentStep;
  }

  normalizeStep(step) {
    step = step || {};
    return {
      name: step.name || "Null step",
      context: loginDefs.stepContext.normalize(step.context),
      code: step.code || "function(){}",
    };
  }

  isLastStep() {
    return !this.steps || this.steps.length <= this.currentStep + 1;
  }

  advanceToNextStep() {
    if (!this.isLastStep()) {
      ++this.currentStep;
      this.stepStartTs = this.currentTime.get();
      if (this.lastActivityTs > 0) {
        this.lastActivityTs = this.stepStartTs;
      }
    } else {
      console.error("Trying to advance past the last step");
    }
  }

  getStepTime() {
    return this.currentTime.get() - this.stepStartTs;
  }
}

export default StepsPhase;
