import { setTimeoutPromisified } from "../timeout.js";

var injectedWaitForReady = function () {
  var lastDomModifiedTime,
    countCheckFnWasFast,
    lastCheckFnTime,
    glob = window,
    startCheckTime = Date.now(),
    READYSTATE_MAX_WAIT = 5000,
    mutationObserver = null;

  if (typeof unsafeWindow !== "undefined") {
    glob = unsafeWindow; // eslint-disable-line no-undef
  }

  function log() {
    if (typeof logger === "object"&& glob.logger.log) {
      logger.log.apply(logger, arguments); // eslint-disable-line no-undef
    }
  }

  function domModifiedObserver(event) {
    lastDomModifiedTime = Date.now();
  }

  function domModified(event) {
    if (event) {
      if (event.target && event.target.nodeName === "SCRIPT") {
        return;
      }
      log("modified: ", event.type, event.target);
    }
    lastDomModifiedTime = Date.now();
  }

  function registerEvents() {
    domModified();
    if (!!window.MutationObserver && typeof MutationObserver === "function") {
      // prefer MutationObserver if available
      mutationObserver = new MutationObserver(domModifiedObserver);
      mutationObserver.observe(document, {
        //attributes: true,
        childList: true,
        characterData: true,
        subtree: true,
      });
    } else {
      document.addEventListener("DOMNodeRemoved", domModified);
      document.addEventListener("DOMNodeInserted", domModified);
    }
  }

  function unregisterEvents() {
    if (mutationObserver != null) {
      mutationObserver.disconnect();
    } else {
      document.removeEventListener("DOMNodeRemoved", domModified);
      document.removeEventListener("DOMNodeInserted", domModified);
    }
  }

  function isLoadFinished() {
    return !glob.performance || (glob.performance.timing && glob.performance.timing.loadEventEnd);
  }

  function checkFn() {
    var current = Date.now();
    if (lastCheckFnTime && Math.abs(current - lastCheckFnTime) < 12) {
      countCheckFnWasFast++;
      if (countCheckFnWasFast > 10) {
        log("by load ready");
        glob.OL_XB_READY_STATE = true;
        unregisterEvents();
        return;
      }
    } else {
      countCheckFnWasFast = 0;
    }
    if (isLoadFinished()) {
      if (current - startCheckTime > READYSTATE_MAX_WAIT || current - lastDomModifiedTime > 2000) {
        //no action for 2 seconds, max wait time 5 seconds
        log("idle");
        glob.OL_XB_READY_STATE = true;
        unregisterEvents();
        return;
      }
    }
    lastCheckFnTime = current;
    setTimeout(function () {
      checkFn();
    }, 10);
  }

  function run() {
    log("start checking ready state");
    glob.OL_XB_READY_STATE = false;
    registerEvents();
    checkFn();
  }

  function onReady() {
    if (document.readyState === "complete") {
      document.removeEventListener("readystatechange", onReady);
      run();
    }
  }

  function init() {
    var result = false;

    if (typeof glob.OL_XB_READY_STATE === "boolean") {
      result = glob.OL_XB_READY_STATE;
      if (glob.OL_XB_READY_STATE) {
        delete glob.OL_XB_READY_STATE;
      }
    } else {
      glob.OL_XB_READY_STATE = false;
      if (document.readyState === "complete") {
        run();
      } else {
        log("waiting for ready");
        document.addEventListener("readystatechange", onReady);
      }
    }
    return result;
  }

  return init();
};

async function waitForReady(tabHandle) {
  async function checkReadyState() {
    const res = await chrome.scripting.executeScript({
      func: injectedWaitForReady,
      target: { tabId: tabHandle },
    });
    if (res) {
      setTimeout(() => {}, 0);
    } else {
      await setTimeoutPromisified(100);
      await checkReadyState();
    }
  }
  await checkReadyState();
}

export default waitForReady;
