/*
  Starts and executes login process.
    Input: tabHandle, login params (contains credentials, loginSteps and testSteps)
    Output: loginProc, result
 */

import loginDefs from "./utils/loginDefs.js";
import EventEmitter from "eventemitter3";
import LoginProcessPool from "./loginProcess/loginProcessPool.js";
import LoginProcessContext from "./loginProcess/loginProcessContext.js";

class LoginWorkflow extends EventEmitter {
  constructor(stepsExecutor) {
    super();

    this.stepsExecutor = stepsExecutor;

    this.loginProcesses = new LoginProcessPool();
    this.loginProcesses.on("loginProcess.timeout", (loginProc) => {
      this.finishStepsProcessing(loginProc, loginDefs.apiResult.FAILURE);
    });
  }

  /**
   * Create a new login process
   * @param tab
   * @param params
   */
  async initiateLoginProcess(tabHandle, params) {
    if (this.loginProcesses.isRunning({ taskId: params && params.taskId })) return;

    var loginProc = new LoginProcessContext(tabHandle, params);
    if (loginProc.isTest()) {
      loginProc.log("Server says this is a test.");
    }
    this.emit("loginProcess.started", loginProc);

    loginProc.log("API version: "+ loginDefs.API_VERSION.display);
    this.loginProcesses.add(loginProc);
    const response = await this.stepsExecutor.executeLoginPhase(
      loginProc
      // this.finishStepsProcessing.bind(this)
    );

    if (response && response.loginProc) {
      await this.finishStepsProcessing(response.loginProc, response.result);
    }
  }

  /**
   * Called once the login process is finished
   * @param loginProc
   * @param result - Result value of the login process (should be either SUCCESS or FAILURE)
   */
  async finishStepsProcessing(loginProc, result) {
    let self = this;
    loginProc.log("Finished "+ loginProc.getPhaseName().toUpperCase() + "phase: "+ result);

    if (loginProc.isInLoginPhase()) {
      this.emit("loginProcess.testStarted", loginProc);
      await this.stepsExecutor.executeTestPhase(loginProc);
      return;
    }

    this.loginProcesses.remove(loginProc);
    loginProc.done();

    this.emit("loginProcess.finished", {
      loginProc: loginProc,
      success: result === loginDefs.apiResult.SUCCESS,
    });
  }

  /*
     returns true, when there is active login process in given tab
     */
  isLoginProcessActive(tabHandle) {
    return this.loginProcesses.isRunning({ tabHandle: tabHandle });
  }
}

export default LoginWorkflow;
