import { Notifier } from "@airbrake/browser";

export class OneloginAirbrake {
  constructor(config) {
    this.config = config;
    this.sourceMaps = {};
    /**
     * Think about getting this value at
     * runtime somehow
     */
    this.releaseType = "production";
  }

  init(airbrakeConfig) {
    this.airbrakeConfig = airbrakeConfig;
    if (!this.airbrakeConfig) {
      console.warn("Airbrake not initialised");
      return;
    }

    if (!this.isEnabled()) {
      return;
    }

    console.log("init airbrake: ", new Date());
    this.airbrake = new Notifier({
      projectId: this.airbrakeConfig.projectId,
      projectKey: this.airbrakeConfig.projectKey,
    });

    /**
     * Add runtime error
     */
    this.airbrake.addFilter(function (notice) {
      var lastErrorMsg =
        !!chrome && !!chrome.runtime && !!chrome.runtime.lastError
          ? chrome.runtime.lastError.message
          : "<no last error set>";
      notice.context.runtimeLastError = lastErrorMsg;
      return notice;
    });

    /**
     * Add runtime environment
     */
    this.airbrake.addFilter(function (notice) {
      notice.context.environment = this.releaseType;
      notice.context.gitHash = this.gitHash;

      return notice;
    });

    /**
     * Add source maps context
     */
    this.airbrake.addFilter(function (notice) {
      notice.context.sourceMaps = this.sourceMaps;
      return notice;
    });
  }

  getOneloginAirbrake() {
    return this.airbrake;
  }

  async notify(err) {
    if (this.isEnabled()) {
      return await this.airbrake.notify(err);
    }
  }

  wrap(fn) {
    if (this.isEnabled()) {
      this.airbrake.wrap(fn);
    }
  }

  isEnabled() {
    if (this.enabled === undefined) {
      switch (this.releaseType) {
        case "shadow":
          this.enabled = true;
          break;
        case "production":
          this.enabled = true;
          break;
        case "development":
          this.enabled = true;
          break;
        case "test":
          this.enabled = false;
          break;
        default:
          this.enabled = false;
          break;
      }
    }
    return this.enabled;
  }
}
