import { parseDomain } from "parse-domain";

const getDomain = (url) => {
  const parsed = parseDomain(url);

  return parsed && parsed.domain;
};

const toQueryString = function (parameters) {
  const searchParams = new URLSearchParams(parameters);
  return searchParams.toString();
};

const getServerDomain = function (portalUrl) {
  // TODO: refactor to use parse-domain
  var match = portalUrl && portalUrl.match(/^(https?:\/\/)([^.]+)\.([^/]+)/);
  if (match && match[1] && match[2] && match[3]) {
    var proto = match[1],
      subdomain = match[2],
      domain = match[3];

    return proto + subdomain + "."+ domain;
  } else {
    //TODO: what to do here?
    console.error("urlHelpers: failed to parse server url by portalUrl", portalUrl);
    return undefined;
    // this.serverUrl = undefined;
  }
};

const getSubdomain = function (serverUrl) {
  var url = parseDomain(serverUrl);
  return url ? `${url.subdomain}.${url.domain}.${url.tld}` : undefined;
};

const isAbsoluteUrl = function (url) {
  return /https?:\/\//.test(url);
};

export default {
  getDomain,
  getServerDomain,
  getSubdomain,
  isAbsoluteUrl,
  toQueryString,
};
