/*
    Helper object to report result of login process to the server.
 */

class LoginResultReporter {
  constructor(oneloginApiServer) {
    this.oneloginApiServer = oneloginApiServer;
  }

  sendToServer(loginProc, success) {
    var reportUrl = loginProc.getReportUrl(),
      accountId = loginProc.getAccountId(),
      taskId = loginProc.getLoginTaskId();

    if (reportUrl === undefined) {
      console.error(
        "Cannot report result reportUrl:",
        reportUrl,
        "accountId:",
        accountId,
        "taskId:",
        taskId
      );
      return;
    }

    loginProc.log("Reporting result to: "+ loginProc.getReportUrl());

    var loginResult = {
      taskId: taskId,
      accountId: accountId,
      result: success,
      details: loginProc.getLog(),
    };

    this.oneloginApiServer
      .request({
        method: "POST",
        url: reportUrl,
        body: loginResult,
        json: true,
      })
      .then((res) => {
        console.log("Result reported.");
      })
      .catch((err) => {
        console.log(`Error reporting result to ${loginProc.getReportUrl()} : `);
        console.log(err);
      });
  }
}

export default LoginResultReporter;
