import request from "../global/request.js";
import portalPageClassifier from "../global/oneloginApiServer/portalPageClassifier.js";

async function getLoginScript(loginUrl) {
  const requestData = {
    method: "GET",
    url: loginUrl,
    json: true,
    headers: {},
  };
  const loginScript = await request.send(requestData);
  console.log("LOGIN SCRUTP : ", loginScript);
  return loginScript;
}

async function initLoginScriptMessageHandler(startUrl, tab, oneloginApiServer, workflow) {
  // this.domainValidator.isOneloginDomainAsync(startUrl).then(isValid => {
  // if (!isValid) {
  if (!portalPageClassifier.isOneloginPortal(startUrl)) {
    // falsy detection of onelogin start login url
    console.log(`Initiate login called on invalid onelogin domain: ${startUrl}`);
    // callback();
    return;
  }

  if (!portalPageClassifier.classifyPortalUrl(startUrl) === "formServiceStartLoginUrl") {
    // should not happen, but to be sure ( could the message be somehow faked?)
    console.error(`Initiate login from invalid URL: ${startUrl}`);
    // callback({ err: { serverMessage: "Invalid start login url."} });

    return { err: { serverMessage: "Invalid start login url."} };
  }

  let loginUrl = null;
  try {
    loginUrl = new URL(startUrl.replace("/start/", "/login/"));
  } catch (e) {
    // should not really happen
    console.error(`Cannot construct get login script url. Start url: ${startUrl}`);
    // callback({ err: { serverMessage: "Cannot construct login url."} });
    return { err: { serverMessage: "Cannot construct login url."} };
  }

  // login can be started also from different OL domain then the current one!
  if (loginUrl.origin !== oneloginApiServer.getServerUrl()) {
    console.log(`Initiating login from different domain then the extension current one?`);
  }

  try {
    const loginScript = await getLoginScript(loginUrl.href);
    if (loginScript) {
      // Workflow handler
      await workflow.initiateLoginProcess(tab, loginScript);
      // callback();
      return;
    }
  } catch (err) {
    return { err };
  }
}

export default initLoginScriptMessageHandler;
