import { setTimeoutPromisified } from "../../global/timeout.js";
import loginDefs from "../utils/loginDefs.js";

/*
  Input: 
    login steps
    context executors

  Goes through login steps and executes them in proper executor 
 */

class StepsExecutor {
  constructor(codeExecutors, stepApiActions) {
    this.stepApiActions = stepApiActions;
    this.codeExecutors = {};
    codeExecutors.forEach((executor) => {
      this.codeExecutors[executor.getContext()] = executor;
    });
  }

  async executeLoginPhase(loginProc) {
    loginProc.startLoginPhase();
    return this.executeStep(loginProc);
  }

  async executeTestPhase(loginProc) {
    loginProc.startTestPhase();
    return this.executeStep(loginProc);
  }

  /**
   * Gets the current step of the login process and executes it in the proper context.
   * @param loginProc
   */
  async executeStep(loginProc) {
    loginProc.touch();
    var step = loginProc.getCurrentStep();

    loginProc.log('Executing step "' + step.name + '"in "' + step.context + '"context...');

    //get step context, find executor, execute or return error
    let codeExecutor = this.codeExecutors[step.context];
    if (codeExecutor) {
      const apiDataOut = await codeExecutor.executeStep(loginProc);
      return this.stepExecutedCallback(apiDataOut.error, loginProc, apiDataOut);
    } else {
      loginProc.logError('"' + step.context + '"context not implemented!');
      return;
    }
  }

  /**
   * Called once the step code finished execution (in any context).
   * @param err - defined if an error occurred
   * @param loginProc
   * @param apiDataOut
   */
  async stepExecutedCallback(err, loginProc, apiDataOut) {
    if (loginProc.isDone()) {
      return;
    }

    if (err) {
      loginProc.logError(
        'Error executing step "' +
          loginProc.getCurrentStep().name +
          '": ' +
          JSON.stringify(err) +
          ""+
          err.toString()
      );
      return {
        loginProc,
        result: loginDefs.apiResult.FAILURE,
      };
    }

    return this.processStepApiAction(loginProc, apiDataOut, 0);
  }

  /**
   * Called once the step code finished execution successfully. Goes through apiDataOut.actions and performs them.
   * @param loginProc
   * @param apiDataOut
   */
  async processStepApiAction(loginProc, apiDataOut, actionIndex) {
    var result = loginDefs.apiResult.normalize(apiDataOut.result);
    if (result === loginDefs.apiResult.NEXT && loginProc.isLastStep()) {
      result = loginDefs.apiResult.SUCCESS;
    }

    // var action =
    //   !!apiDataOut.actions &&
    //   apiDataOut.actions.length > actionIndex &&
    //   apiDataOut.actions[actionIndex];
    var action =
      apiDataOut.actions && apiDataOut.actions.length > actionIndex
        ? apiDataOut.actions[actionIndex]
        : false;

    if (!!action) {
      var actionFunc = this.stepApiActions[action.type].bind(this.stepApiActions);
      if (!!actionFunc) {
        try {
          result = await actionFunc(action.param, loginProc);
          return this.processStepApiAction(loginProc, apiDataOut, actionIndex + 1);
        } catch (error) {
          loginProc.log('ERROR in api action "' + action.type + '": ' + err);
          return {
            loginProc,
            result: loginDefs.apiResult.FAILURE,
          };
        }
      } else {
        loginProc.logError("No action func: "+ JSON.stringify(action));
        return this.processStepApiAction(loginProc, apiDataOut, actionIndex + 1);
      }
    }

    loginProc.setUserContext(apiDataOut.userContext || {});
    if (typeof window != "undefined"&& !!window.bgLog) {
      window.bgLog("loginProc.setUserContext (apiDataOut): "+ JSON.stringify(apiDataOut));
    }

    if (result === loginDefs.apiResult.SUCCESS || result === loginDefs.apiResult.FAILURE) {
      // finishStepsCallback(loginProc, result);
      // return;
      return {
        loginProc,
        result,
      };
    }

    if (result === loginDefs.apiResult.NEXT) {
      loginProc.advanceToNextStep();
      return this.executeStep(loginProc);
    } else {
      // result === loginDefs.apiResult.WAIT
      await setTimeoutPromisified(100);
      return this.executeStep(loginProc);
    }
  }
}

export default StepsExecutor;
