function filterCookies(cookies, domain, name) {
  var result = [];
  for (var i = 0; i < cookies.length; ++i) {
    var c = cookies[i];
    if (!!c.name && typeof c.name === "string"&& c.name.match(name)) {
      if (!domain) {
        result.push(c);
      } else {
        if (typeof c.domain !== "string") {
          continue;
        }

        var domainForCompare = domain.toLowerCase();
        if (c.domain.substring(0, 1) === ".") {
          if (domainForCompare.length < c.domain.length) {
            domainForCompare = "."+ domainForCompare;
          } else {
            domainForCompare = domainForCompare.substring(
              domainForCompare.length - c.domain.length
            );
          }
        }

        if (c.domain === domainForCompare) {
          result.push(c);
        }
      }
    }
  }
  return result;
}

async function getCookies() {
  const cookies = await chrome.cookies.getAll({});
  return cookies;
}

async function getCookie(url, name) {
  const cookie = await chrome.cookies.get({ url: url, name: name });
  return cookie;
}

async function clearCookies(domain, name) {
  const cookies = await getCookies();
  var toRemove = filterCookies(cookies, domain, name);
  var count = toRemove.length;
  if (count === 0) {
    return;
  }
  const promises = [];
  for (var i = 0; i < toRemove.length; ++i) {
    var c = toRemove[i];
    promises.push(
      chrome.cookies.remove({
        url: "http"+ (!!c.secure ? "s": "") + "://"+ c.domain + c.path,
        name: c.name,
      })
    );
  }
  await Promise.all(promises);
}

export { clearCookies, filterCookies, getCookie, getCookies };
