import EventEmitter from "eventemitter3";

CurrentUser.prototype = new EventEmitter();

/*

Example of current user structure:
{
    _id: "123456",
    email: "tomas.soukup@onelogin.com",
    fullName: "Tomas Soukup",
    userSettings: {
        tab_enabled: true
    },
    userFeatures: {  //these are gone when user signs out
        FF_DROPDOWN_MENU: true
    },
    globalFeatures: { //featureFlags valid also when user is signed out
        FF_CACHE_DROPDOWN_MENU: true
    }
}

 */

CurrentUser.prototype.get = function () {
  return this.user;
};

CurrentUser.prototype.getCompanyName = function () {
  return this.user.company && this.user.company.name;
};

CurrentUser.prototype.getSubdomain = function () {
  return this.oneloginApiServer && this.oneloginApiServer.getSubdomain();
};

CurrentUser.prototype.getUserDebugName = function (user) {
  return user.email || user.username;
};

CurrentUser.prototype.set = function (user) {
  this.user = user || {};
  console.log("Set user:", this.getUserDebugName(this.user));
  // this.emit("currentUser.set", this.user); //deprecated; used only in tests
};

CurrentUser.prototype.hasFeature = function (featureName) {
  if (!featureName) {
    return false;
  }

  if (this.user?.userFeatures?.hasOwnProperty(featureName)) {
    return !!this.user.userFeatures[featureName];
  }

  if (this.user?.globalFeatures?.hasOwnProperty(featureName)) {
    return !!this.user.globalFeatures[featureName];
  }

  return false;
};

CurrentUser.prototype.getUserSetting = function (settingName) {
  return this.getUserSettings()[settingName];
};

CurrentUser.prototype.getUserSettings = function () {
  return this.user.userSettings || {};
};

CurrentUser.prototype.logout = function () {
  this.set({ globalFeatures: this.user.globalFeatures }); //maintain globalFeatures even if user is loged out
};

CurrentUser.prototype.hasValidSession = async function () {
  return this.oneloginApiServer.isSessionValid();
};

CurrentUser.prototype.isAuthenticated = function () {
  return this.user.email && this.oneloginApiServer.isAuthenticated();
};

CurrentUser.prototype.updateSettings = async function (settings) {
  var self = this;
  const response = await this.oneloginApiServer.request({
    method: "PUT",
    url: "/form-service/settings",
    json: true,
    body: { app_auto_detect: settings.app_auto_detect },
  });
  return response;
};

CurrentUser.prototype.reinit = async function () {
  var self = this;
  console.log("Called reinit user");
  try {
    const response = await self.oneloginApiServer.request({
      url: "/form-service/me",
      json: true,
    });
    console.log("Response : ", response);
    self.set(response);
  } catch (err) {
    if (err.status === 401) {
      console.log("User is not authorized");
      self.logout();
    } else {
      console.log(err);
      console.error(
        "Failed to reinit current user. Using previous:",
        self.getUserDebugName(self.user)
      );
    }
  }
};

function CurrentUser(oneloginApiServer) {
  this.oneloginApiServer = oneloginApiServer;
  this.set({});
}

export default CurrentUser;
