/*
 Execute login step in content context of the extension.
 Inject the content script into page and execute the step.
 */

import loginDefs from "../utils/loginDefs.js";
import oneloginTabs from "../../global/tabs/oneloginTabs.js";
import { getBrowserCapabilities } from "../../global/capabilities.js";

/**
 * Added retry logic since for few apps/connectors the message channel between background and content script used to break after one successful login.:
 * 1 .The page is being placed into the Back/Forward Cache (BFCache).
 * 2. The background script is trying to send a response, but the page is suspended, causing the message channel to close.
 * 3. For some apps like TrustPilot the login page redirects to a different page and the message channel is closed since the previous page is removed form the tab's context
 */
async function sendMessageToTabWithRetry(tabHandle, apiDataIn, currentStepIndex) {
  const MAX_RETRIES = 3;
  let retryCount = 0;
  let lastError = null;
  while (retryCount < MAX_RETRIES) {
    try {
      // Check if the tab is still valid before sending a message
      const tab = await chrome.tabs.get(tabHandle);
      if (!tab || !tab.url) {
        throw new Error("Tab no longer exists or has no URL");
      }

      // Refresh the tab info in case it has changed
      const currentTabInfo = await oneloginTabs.getTabInfo(tabHandle);

      const apiDataOut = await chrome.tabs.sendMessage(tabHandle, {
        apiDataIn: apiDataIn,
        url: currentTabInfo.url,
        browserCapabilities: apiDataIn.about.capabilities,
        currentStepIndex: currentStepIndex,
      });
      console.log(`Result for step ${currentStepIndex} : `, apiDataOut);
      return apiDataOut;
    } catch (error) {
      lastError = error;
      console.log(`Attempt ${retryCount + 1} failed: ${error.message}`);
      // Check if this is a connection error related to bfcache
      if (
        error.message.includes("message channel is closed") ||
        error.message.includes("Extension context invalidated")
      ) {
        // Wait a bit before retrying with increasing delay
        await new Promise((resolve) => setTimeout(resolve, 500 * (retryCount + 1)));
        // Try to re-establish connection without reloading
        try {
          // Focus the tab to potentially bring it out of bfcache
          await chrome.tabs.update(tabHandle, { active: true });
          // Additional wait after focusing the tab
          await new Promise((resolve) => setTimeout(resolve, 300));
        } catch (focusError) {
          console.error("Failed to focus tab:", focusError);
        }

        retryCount++;
        continue;
      }

      // For other types of errors, don't retry
      console.error("Error in executing login flow : ", error);
      throw error;
    }
  }

  // If we've exhausted all retries
  console.error("Error in executing login flow after multiple retries: ", lastError);
  throw lastError;
}

class ContentExecutor {
  constructor() {}

  getContext() {
    return loginDefs.stepContext.CONTENT;
  }

  async executeStep(loginProc) {
    var tabHandle = loginProc.getTabHandle();
    var apiDataIn = loginProc.getApiContext();
    var currentStepIndex = loginProc.getCurrentStepIndex();
    const tabInfo = await oneloginTabs.getTabInfo(tabHandle);
    apiDataIn.about.capabilities = getBrowserCapabilities();
    apiDataIn.location = tabInfo.url;
    /**
     * The injectedMethodUS.js and injectedMethodEU.js content script injection are shifted to manifest.json file.
     * Reason:
     * 1. The message channel between background and content script used to break after one successful login for some apps/connectors (eg: J-motto)
     * 2. The content script injection via manifest is considered more reliable and stable.
     */

    return sendMessageToTabWithRetry(tabHandle, apiDataIn, currentStepIndex);
  }
}

export default ContentExecutor;
