import inMemoryCache from "../global/storage/cache.js";

export async function getAccountsFromServer(oneloginApiServer, readFromCache = true) {
  try {
    if (readFromCache) {
      console.log("reading apps from cache");
      let appsList = inMemoryCache.get(`APPS_LIST`);
      if (appsList) {
        return appsList;
      }
    }
    const response = await oneloginApiServer.request({
      method: "GET",
      url: "/form-service/logins",
      json: true,
      requestTimeout: 120000,
    });
    inMemoryCache.set(`APPS_LIST`, response);
    return response;
  } catch (error) {
    console.warn("error fetching user accounts: ", error.message);
    throw error;
  }
}
