/*
  Holds context and state of currently executed login process
 */

import loginDefs from "../utils/loginDefs.js";
import CurrentTime from "../utils/currentTime.js";
import StepsPhase from "./stepsPhase.js";

class LoginProcessContext {
  constructor(tabHandle, params) {
    this.currentTime = new CurrentTime();
    let now = this.currentTime.get();

    this.tabHandle = tabHandle;

    this.active = true;
    this.createdTs = now;
    this.lastAccessTs = now;
    this.stepStartTs = now;
    this.lastActivityTs = now;

    this.params = params || {};
    this.userContext = {};
    this.wwwAuthenticationPerformed = false;

    this.logMessages = [];
    this.log("Login process created: "+ this.getUserAgent()); //TODO: getUserAgent
    this.log("Login type: "+ params.loginType);

    this.navigating = false;
  }

  getUserAgent() {
    if (typeof navigator !== "undefined") {
      return navigator.userAgent;
    }
    return "unknown";
  }

  log(message) {
    var msg = "["+ ((this.currentTime.get() - this.createdTs) / 1000).toFixed(6) + "]  "+ message;
    this.logMessages.push(msg);
    console.log(msg);
  }

  logError(message) {
    this.log("ERROR: "+ message);
  }

  getLog() {
    var result = "";
    for (var i = 0; i < this.logMessages.length; ++i) {
      result += this.logMessages[i] + "\n";
    }
    return result;
  }

  getReportUrl() {
    return this.params.reportUrl || undefined;
  }

  getAccountId() {
    return this.params.accountId || undefined;
  }

  getLoginTaskId() {
    return this.params.taskId || undefined;
  }

  getTabHandle() {
    return this.tabHandle;
  }

  setTabHandle(newTabId) {
    this.tabHandle = newTabId;
  }

  getVariables() {
    return this.params.variables || undefined;
  }

  getUserContext() {
    return this.userContext;
  }

  getTotalTime() {
    return this.currentTime.get() - this.createdTs;
  }

  getWWWAuthenticationPerformed() {
    return !!this.wwwAuthenticationPerformed;
  }

  setWWWAuthenticationPerformed(value) {
    this.wwwAuthenticationPerformed = !!value;
  }

  getApiContext() {
    return {
      about: {
        version: loginDefs.API_VERSION,
      },
      totalTime: this.getTotalTime(),
      stepTime: this.phase.getStepTime(),
      // idleTime: loginProc.getIdleTime(),
      userContext: this.getUserContext(),
      variables: this.getVariables(),
      wasWWWAuthenticationPerformed: this.getWWWAuthenticationPerformed(),
      v3_extension: this.params.v3_extension,
      mainLoginType: this.params.mainLoginType,
      connectorId: this.params.connectorId,
    };
  }

  setUserContext(userContext) {
    this.userContext = userContext;
  }

  touch(now) {
    this.lastAccessTs = now || this.currentTime.get();
  }

  isExpired(now) {
    now = now || this.currentTime.get();
    return this.lastAccessTs + loginDefs.EXPIRE_TIME < now;
  }

  isTest() {
    return !!(this.params.variables && this.params.variables.test);
  }

  done() {
    this.active = false;
  }

  isDone() {
    return !this.active;
  }

  startLoginPhase() {
    this.phase = new StepsPhase(loginDefs.LOGIN_PHASE, this.params.steps);
    this.log("Started login phase.");
  }

  startTestPhase() {
    this.phase = new StepsPhase(loginDefs.TEST_PHASE, this.params.testSteps);
    this.log("Started test phase.");
  }

  isInLoginPhase() {
    return this.phase.getName() === loginDefs.LOGIN_PHASE;
  }

  isInTestPhase() {
    return this.phase.getName() === loginDefs.TEST_PHASE;
  }

  getPhaseName() {
    return this.phase.getName();
  }

  getCurrentStep() {
    return this.phase.getCurrentStep();
  }

  getCurrentStepIndex() {
    return this.phase.getCurrentStepIndex();
  }

  isLastStep() {
    return this.phase.isLastStep();
  }

  advanceToNextStep() {
    return this.phase.advanceToNextStep();
  }

  setNavigating(navigating) {
    this.navigating = navigating;
  }

  isNavigating() {
    return this.navigating;
  }

  touchLastActivity() {
    this.lastActivityTs = this.currentTime.get();
  }

  clearLastActivity() {
    this.lastActivityTs = 0;
  }

  getIdleTime() {
    return this.lastActivityTs > 0 ? this.currentTime.get() - this.lastActivityTs : 0;
  }
}

export default LoginProcessContext;
