import { getAccountsFromServer } from "./accounts.js";
import initLogin from "../login/initLoginScriptMessageHandler.js";
import perform_login_wrapper from "../trainer/trainer_script.js";

export function handleMessage(config, oneloginApiServer, actionHandler, workflow, currentUser) {
  var isLoginProcessActive;
  var eventName = config.eventName,
    eventParams = config.eventParams,
    callback = config.callback,
    tabHandler = config.tabHandler;

  switch (eventName) {
    case "onelogin.getServerInfo":
      var response = {
        serverUrl: oneloginApiServer.getServerUrl(),
      };
      console.log("onelogin.getServerInfo: ", response);
      callback(null, response);
      break;
    case "onelogin.getAccounts":
      console.log("onelogin.getAccounts: ", config);
      getAccountsFromServer(oneloginApiServer)
        .then((res) => {
          console.log("onelogin.getAccounts:", res);
          callback(null, res);
        })
        .catch((err) => {
          console.warn("onelogin.getAccounts:", err.message);
          callback(err, null);
        });
      return true;
    case "onelogin.portalMessage":
      console.log("onelogin.portalMessage: ");
      actionHandler
        .handleAction(eventParams)
        .then((res) => {
          callback(null, res);
        })
        .catch((err) => callback(err, null));
      return true;
    case "onelogin.openPortal":
      console.log("onelogin.openPortal");
      actionHandler
        .handleAction({ type: "selectPortalTab"})
        .then((res) => {
          callback(null, res);
        })
        .catch((err) => callback(err, null));
      return true;
    case "onelogin.initLogin":
      console.log("onelogin.initLogin for: ", eventParams.startUrl);
      initLogin(eventParams.startUrl, tabHandler, oneloginApiServer, workflow)
        .then((res) => {
          if (res && res.err) {
            callback(res.err, null);
            return;
          }
          callback(null, res);
        })
        .catch((err) => callback(err, null));
      return true;
    case "onelogin.getExtensionVersionString":
      console.log("onelogin.getExtensionVersionString");
      actionHandler
        .handleAction({ type: "getExtensionVersion"})
        .then((res) => {
          callback(null, res);
        })
        .catch((err) => callback(err, null));
      return true;
    case "onelogin.isLoginProcessActive":
      isLoginProcessActive = workflow.isLoginProcessActive(tabHandler);
      console.log("onelogin.isLoginProcessActive: ", isLoginProcessActive);
      callback(null, { isLoginProcessActive });
      return;
    case "onelogin.getUserSettings":
      console.log("onelogin.getUserSettings");
      callback(null, currentUser.getUserSettings());
      return;
    case "onelogin.getTrainerDialogInfo":
      console.log("onelogin.getTrainerDialogInfo");
      oneloginApiServer
        .request({
          method: "GET",
          url: `${eventParams.serverUrl}/client/apps/signon?sites=trainer&current_url=${encodeURIComponent(eventParams.currentLocation)}`,
        })
        .then((res) => {
          callback(null, res);
        })
        .catch((err) => callback(err));
      return true;
    case "onelogin.injectTrainerDialogScript":
      console.log("onelogin.injectTrainerDialogScript");

      oneloginApiServer
        .request({
          method: "GET",
          url: `${eventParams.serverUrl}/api/v3/sessions/get_form_authenticity_token`,
          json: true,
        })
        .then(async (res) => {
          const tabArray = await chrome.tabs.query({
            currentWindow: true,
            active: true,
          });
          let tab = tabArray[0];
          chrome.scripting
            .executeScript({
              target: { tabId: tab.id },
              func: perform_login_wrapper,
              args: [eventParams.serverUrl, res.form_authenticity_token],
            })
            .then(() => console.log("injected and executed trainer script"))
            .catch(console.error);
        })
        .catch((err) => {
          console.log(`error fetching form authenticity token: `, err);
          callback(err);
        });
      return true;
    case "onelogin.currentContext":
      const extensionUrl = chrome.runtime.getURL("");
      console.log("onelogin.currentContext: ", extensionUrl);
      callback(null, { extensionUrl });
      return;
  }

  /**
   * return true from the handlers for async operations
   */
}
