class CurrentTime {
  constructor() {
    if (
      typeof window !== "undefined"&&
      typeof window.performance !== "undefined"&&
      typeof window.performance.now !== "undefined"
    ) {
      this.get = function () {
        return window.performance.now();
      };
    } else {
      this.get = (function () {
        var st = Date.now();
        return function () {
          return Date.now() - st;
        };
      })();
    }
  }
}

export default CurrentTime;
