import EventEmitter from "eventemitter3";
import urlHelpers from "../urlHelpers.js";
import xbrowserRequest from "../request.js";

var DEFAULT_SERVER_URL = "https://app.onelogin.com/login"; // default server URL when not found in local storage nor in cookies

OneloginApiServer.prototype = new EventEmitter();

//TODO: this should be better named as FormServiceServer?
OneloginApiServer.prototype.getUrl = function (relativePath) {
  return relativePath ? this.serverUrl + relativePath : this.serverUrl;
};

OneloginApiServer.prototype.setAuthenticated = function (authenticated) {
  this.authenticated = authenticated;
  console.log("oneloginApiServer: setting authenticated to", this.authenticated);
};

OneloginApiServer.prototype.isAuthenticated = function () {
  return this.authenticated;
};

OneloginApiServer.prototype.logout = function (url) {
  console.log("oneloginApiServer: logout", url);
  this.serverUrl = url ? urlHelpers.getServerDomain(url) : this.serverUrl;

  this.setXSessionHeaders(undefined);
  // if (!this.isAuthenticated()) {
  //     console.log("oneloginApiServer: logout ignored, not authenticated");
  //     return;
  // }

  this.setAuthenticated(false);
  console.log("oneloginApiServer emit: 'oneloginApiServer.logout'");
  this.emit("oneloginApiServer.logout");
};

OneloginApiServer.prototype.setXSessionHeaders = function (session) {
  if (session) {
    console.log("oneloginApiServer: set session headers");
    this.defaultHeaders = { "X-Onelogin-Session": session };
  } else {
    console.log("oneloginApiServer: clean session headers");
    this.defaultHeaders = {};
  }
};

OneloginApiServer.prototype.isSessionValid = async function () {
  const response = await this.request({
    method: "GET",
    url: "/form-service/me",
    json: true,
  });
  return true;
};

OneloginApiServer.prototype.login = function (url) {
  let serverUrl = urlHelpers.getServerDomain(url);

  //same server, authenticated - do not trigger further actions
  if (serverUrl === this.serverUrl && this.isAuthenticated()) {
    console.log("oneloginApiServer: login ignored, same url and authenticated");
    return;
  }

  this.serverUrl = serverUrl;

  //assuming that I am authenticated when changing server with specific subdomain
  this.setAuthenticated(true);
  console.log("oneloginApiServer: set server url:", this.serverUrl);

  console.log("oneloginApiServer emit: 'oneloginApiServer.login'");
  this.emit("oneloginApiServer.login", this.serverUrl);
};

OneloginApiServer.prototype.init = function (url) {
  this.login(url); //lets assume, that user is still signed to latest portal
  //TODO: we can later first check session, however now it would result in calling /me twice (on login there is currentUser.reinit)
};

OneloginApiServer.prototype.getAbsoluteUrl = function (url) {
  return urlHelpers.isAbsoluteUrl(url) ? url : this.getUrl(url);
};

OneloginApiServer.prototype.getSubdomain = function () {
  if (this.serverUrl) {
    const subdomain = urlHelpers.getSubdomain(this.serverUrl);
    if (subdomain) {
      return subdomain;
    } else {
      console.error(`oneloginApiServer: unparseable serverUrl -- ${this.serverUrl}`);
      return undefined;
    }
  } else {
    return undefined;
  }
};

OneloginApiServer.prototype.getRequestParams = function (params) {
  let url = this.getAbsoluteUrl(params.url),
    requestData = {
      method: params.method,
      url: url + urlHelpers.toQueryString(params.qs), //TODO: qs should be moved to xbrowserRequest
      json: params.json,
      xml: params.xml,
      headers: { ...this.defaultHeaders },
      requestTimeout: params.requestTimeout,
    };

  if (params.body) {
    requestData.body = params.json ? JSON.stringify(params.body) : params.body;
  }

  return requestData;
};

OneloginApiServer.prototype.getServerUrl = function () {
  return this.serverUrl || DEFAULT_SERVER_URL;
};

OneloginApiServer.prototype.request = async function (params) {
  console.log("oneloginApiServer: requesting '%s'", params.url);

  if (!params.forceRequest && !this.authenticated) {
    console.log("oneloginApiServer: skipping request, extension is not authenticated");
    let err = new Error("Not authenticated");
    err.status = 401;
    throw err;
  }

  const self = this,
    // xbrowserRequest = this.requestFactory(),
    requestParams = this.getRequestParams(params);

  console.log("oneloginApiServer: sending request '%s' to the server", requestParams.url);
  try {
    const response = await xbrowserRequest.send(requestParams);
    return response;
  } catch (err) {
    if (err.status === 401) {
      console.log("oneloginApiServer: Server returned: 401 Unauthorized");
      self.logout();
    } else {
      console.error(
        "oneloginApiServer: Failed to send request to",
        requestParams.url,
        ":",
        err.message
      );
    }
    throw err;
  }
};

function OneloginApiServer() {
  this.authenticated = false;
  this.defaultHeaders = {};
}

export { OneloginApiServer };
