/*
  Holds and cleans-up currently running login processes. Offers methods to query running processes. 
 */

import EventEmitter from "eventemitter3";

class LoginProcessPool extends EventEmitter {
  constructor() {
    super();
    this.loginProcesses = [];
    this.periodicallyCheckLoginProcesses();

    // tabs.onReplaced not supported by firefox -> leads to warning in firefox console
    var self = this;
    chrome.tabs.onReplaced.addListener(function (newTabId, oldTabId) {
      if (newTabId !== oldTabId) {
        // update the login process tabId by the new tabId (happens on Edge when navigating between different security zones)
        for (var i = 0; i < self.loginProcesses.length; ++i) {
          if (
            !self.loginProcesses[i].isDone() &&
            self.loginProcesses[i].getTabHandle() === oldTabId
          ) {
            // TODO: report to AirBrake?
            console.warn(
              `Tab id of the login process tab has changed (tabs.onReplaced event): ${oldTabId} -> ${newTabId}`
            );
            return;
          }
        }
      }
    });
  }

  isRunning(query) {
    if (!query.taskId && !query.tabHandle) return false;

    for (var i = 0; i < this.loginProcesses.length; ++i) {
      if (
        !this.loginProcesses[i].isDone() &&
        ((query.taskId && this.loginProcesses[i].getLoginTaskId() === query.taskId) ||
          (query.tabHandle && this.loginProcesses[i].getTabHandle() === query.tabHandle))
      ) {
        return true;
      }
    }

    return false;
  }

  add(loginProc) {
    this.loginProcesses.push(loginProc);
  }

  remove(loginProc) {
    var index = this.loginProcesses.indexOf(loginProc);
    if (index > -1) {
      this.loginProcesses.splice(index, 1);
    }
  }

  /**
   * Maintenance of login processes (remove old/stalled)
   */
  periodicallyCheckLoginProcesses() {
    let self = this;
    this.loginProcesses.forEach(function (loginProc) {
      if (loginProc.isExpired()) {
        loginProc.logError("Timed out");

        self.emit("loginProcess.timeout", loginProc);
      }
    });

    setTimeout(this.periodicallyCheckLoginProcesses.bind(this), 120000);
  }
}

export default LoginProcessPool;
