import localStorage from "./local.js";
import { getCookie } from "./cookies.js";

/*
 Last portal url storage.
 This helper function helps to get the last stored portal page
 */

var DEPRECATED_SUBDOMAIN = /^(https?:\/\/app\.onelogin(-shadow\d*)?\.(com|us|dev(:3000)?)).*$/;

async function get() {
  let result = await localStorage.get("OLSubdomain");
  let subdomainUrl = result && typeof result == "object"? result["OLSubdomain"] : undefined;
  console.log("Subdomain url : ", subdomainUrl);
  if (!!subdomainUrl) {
    return subdomainUrl;
  }

  const cookie = await getCookie("https://onelogin.com", "subdomain");
  console.log("Cookie : ", cookie);
  if (!!cookie) {
    console.log(`Subdomain from cookie: ${cookie.value}`);
    subdomainUrl = `https://${cookie.value}.onelogin.com/client/apps`;
  } else {
    // no subdomain found (this can be valid state) -> default URL will be used for popup (see oneloginApiServer)
    subdomainUrl = null; // explicitly set null
    console.log("No subdomain was found in local storage nor in cookie.");
  }
  return subdomainUrl;
}

async function set(url) {
  if (!url.match(DEPRECATED_SUBDOMAIN)) {
    await localStorage.set("OLSubdomain", url);
  }
  return;
}

async function remove() {
  await localStorage.remove("OLSubdomain");
}

export default { get, set, remove };
