import inMemoryCache from "../global/storage/cache.js";
import portalPageClassifier from "../global/oneloginApiServer/portalPageClassifier.js";
import { getAccountsFromServer } from "./accounts.js";
import { VERSION } from "../const.js";

class ActionHandler {
  constructor({ oneloginApiServer, currentUser, subdomainUrl, oneloginTabs }) {
    this.oneloginApiServer = oneloginApiServer;
    this.subdomainUrl = subdomainUrl;
    this.currentUser = currentUser;
    this.oneloginTabs = oneloginTabs;
    this._reinitAccountParams();
  }

  async handleAction(actionParams) {
    //note: legacy portal is handled by userNavigationTracker
    let omit = { ...actionParams };
    delete omit.type;
    console.log(`handleAction: ${actionParams.type}, params: ${JSON.stringify(omit)}`);
    switch (actionParams.type) {
      case "userInitialized":
        this._relogin(actionParams.url);
        break;
      case "reinitUser":
        this._reinitUser();
        break;
      case "getExtensionVersion":
        return { versionString: VERSION };
      /*
        I discovered why this "logoutUser"was previously commented out. oneloginApiServer.logout emits
        a logout message that this actionHandler listens to and calles oneloginApiServer.logout and blows the stack
      */
      // case "logoutUser":
      case "userLogout":
        this._logout(actionParams.url);
        break;
      case "selectPortalTab":
        const response = await this._selectPortalTab();
        return response;
      case "appsChanged": //some app was changed (renamed, removed, added), so invalidate and reload apps
        inMemoryCache.invalidateCache();
        const res = await getAccountsFromServer(this.oneloginApiServer, false);
        return res;
      case "appsFetched": //portal notified of apps loaded
      case "getAccounts": //extension clicked -> new apps are requested to be displayed
        const apps = await getAccountsFromServer(this.oneloginApiServer);
        return apps;
    }
  }

  _reinitAccountParams() {
    this.accountParams = {
      forceFromCache: this.currentUser.hasFeature("FF_DROPDOWN_FORCE_CACHE"),
      forceFromServer: this.currentUser.hasFeature("FF_DROPDOWN_FORCE_SERVER"),
    };
  }

  _logout(url) {
    this.currentUser.logout();
    this.oneloginApiServer.logout(url);
    inMemoryCache.invalidateCache();
  }

  _relogin(url) {
    this.subdomainUrl.set(url);
    this.oneloginApiServer.login(url);
  }

  _reinitUser() {
    this.currentUser.reinit().then(() => {
      this._reinitAccountParams();
    });
  }

  async _selectPortalTab() {
    const tabs = await this.oneloginTabs.getAllPortalTabs();
    if (!!tabs && tabs.length > 0) {
      var tab = tabs[tabs.length - 1];
      await this.oneloginTabs.activate(tab);
      // don't reload portal page, when session is valid or the tab is the portal login page
      if (
        !this.oneloginApiServer.isAuthenticated() &&
        portalPageClassifier.classifyPortalUrl(tab.url) != "portalLoginUrl"
      ) {
        this.oneloginTabs.reload(tab);
      }
      return {
        portalTabSelected: true,
        noPortalTab: false,
        serverUrl: this.oneloginApiServer.getServerUrl(),
      };
    } else {
      // open the newUrl by popup, which decides whether to reuse current tab (e.g. blank page) or open a new one
      return {
        portalTabSelected: false,
        noPortalTab: true,
        serverUrl: this.oneloginApiServer.getServerUrl(),
      };
    }
  }
}

export default ActionHandler;
