/*
     Actions offered in the login steps API, that are executed by the extension (using Backgroun or Content executors).
     The API for these actions are defined in createApiFunctions.
 */

import loginDefs from "./loginDefs.js";
import oneloginTabs from "../../global/tabs/oneloginTabs.js";
import { clearCookies } from "../../global/storage/cookies.js";
import browserWaitForReady from "../../global/tabs/ready.js";
import { uncloakTab } from "../../global/tabs/cloak.js";
import { setTimeoutPromisified } from "../../global/timeout.js";

class StepApiActions {
  constructor() {}

  async log(param, loginProc) {
    loginProc.log('Step "' + loginProc.getCurrentStep().name + '": ' + param);
    // callback();
    return;
  }

  async setLocation(param, loginProc, result) {
    var tabHandle = loginProc.getTabHandle();

    loginProc.log("Setting location: "+ param.url);
    if (param.username && param.password) {
      loginProc.log("www authentication will be used if requested by server.");
    }
    if (result !== loginDefs.apiResult.SUCCESS && result !== loginDefs.apiResult.FAILURE) {
      const authenticationPerformed = await oneloginTabs.setTabUrl(tabHandle, param);
      loginProc.setWWWAuthenticationPerformed(authenticationPerformed);
      if (authenticationPerformed) {
        loginProc.log("www authentication successful");
      }
    } else {
      await oneloginTabs.setTabUrl(tabHandle, param);
    }
  }

  async clearCookie(param, loginProc, result) {
    var name = param.name;
    if (!!param.regExp) {
      // http://stackoverflow.com/questions/874709/converting-user-input-string-to-regular-expression
      var flags = param.regExp.replace(/.*\/([gimy]*)$/, "$1");
      var pattern = param.regExp.replace(new RegExp("^/(.*?)/"+ flags + "$"), "$1");
      name = new RegExp(pattern, flags);
    }
    loginProc.log("Clearing cookies: domain: "+ param.domain + "name: "+ name);
    return clearCookies(param.domain, name);
  }

  async waitForReady(param, loginProc, result) {
    loginProc.log("Executing waitForReady");
    var doWaitForReady = async function () {
      await browserWaitForReady(loginProc.getTabHandle());
      if (loginProc.isNavigating() && !loginProc.isDone()) {
        loginProc.log("Executing waitForReady again, tab is navigating");
        // setTimeout(doWaitForReady, 0);
        await setTimeoutPromisified(10);
        await doWaitForReady();
      } else {
        return;
      }
    };
    await doWaitForReady();
  }

  /**
   * I think CLOAK is not used anywhere
   * Consider this laterrrrrrrrrrrrrrrr
   */
  async cloak(param, loginProc, result) {}

  async uncloak(param, loginProc, result) {
    await uncloakTab(loginProc.getTabHandle());
    console.log("Cloaking endeed");
    return;
  }
}

export default StepApiActions;
