import BackgroundExecutor from "./codeExecutors/backgroundExecutor.js";
import ContentExecutor from "./codeExecutors/contentExecutor.js";
import StepsExecutor from "./codeExecutors/stepsExecutor.js";
import LoginWorkflow from "./loginWorkflow.js";
import LoginResultReporter from "./utils/loginResultReporter.js";
import StepApiActions from "./utils/stepApiActions.js";
import oneloginTabs from "../global/tabs/oneloginTabs.js";
import { uncloakTab } from "../global/tabs/cloak.js";
import XBrowserConst from "../global/tabs/const.js";

function initWorkflow(oneloginApiServer) {
  let loginResultReporter = new LoginResultReporter(oneloginApiServer);
  let contentExecutor = new ContentExecutor();
  let backgroundExecutor = new BackgroundExecutor();
  let stepApiActions = new StepApiActions();
  let stepsExecutor = new StepsExecutor([contentExecutor, backgroundExecutor], stepApiActions);
  let loginWorkflow = new LoginWorkflow(stepsExecutor);

  loginWorkflow.on("loginProcess.finished", function (result) {
    loginResultReporter.sendToServer(result.loginProc, result.success);
    oneloginTabs.clearTabListener(result.loginProc.getTabHandle());
  });

  loginWorkflow.on("loginProcess.testStarted", function (loginProc) {
    uncloakTab(loginProc.getTabHandle()); // just in case
  });

  loginWorkflow.on("loginProcess.started", function (loginProc) {
    if (loginProc.isTest()) {
      // Not implemented yet
      // oneloginTabs.closeOtherTabs(loginProc.getTabHandle());
    }

    let isNavigatingCallback = function (tabHandle, status, info) {
      if (status === XBrowserConst.tabState.NAVIGATING) {
        loginProc.setNavigating(true);
        loginProc.log("Started navigating: ");
      }

      if (status === XBrowserConst.tabState.LOADED) {
        loginProc.touchLastActivity();
        loginProc.log("Finished loading: ");

        if (loginProc.isNavigating()) {
          loginProc.setNavigating(false);
          loginProc.log("Finished navigating: ");
        }
      } else if (status === XBrowserConst.tabState.LOADING) {
        loginProc.clearLastActivity();
        loginProc.log("Started loading: ");
      }
    };

    oneloginTabs.setTabListener(loginProc.getTabHandle(), isNavigatingCallback);
  });
  return loginWorkflow;
}

export default initWorkflow;
