/*
    Constants and definitions used in loginWorkflow
 */

let defs = {
  API_VERSION: {
    // 0.2: added authParams parameter to api.setLocation
    // 0.3: added api.wasWWWAuthenticationPerformed
    //      added api.isMinimumVersion
    major: 0,
    minor: 3,
    display: "0.3",
  },

  EXPIRE_TIME: 120000,
  LOGIN_PHASE: "login",
  TEST_PHASE: "test",

  apiResult: {
    NEXT: "next",
    WAIT: "wait",
    SUCCESS: "success",
    FAILURE: "failure",

    normalize: function (value) {
      value = value ? value.toLowerCase() : undefined;
      if (
        value === defs.apiResult.WAIT ||
        value === defs.apiResult.SUCCESS ||
        value === defs.apiResult.FAILURE
      ) {
        return value;
      }
      return defs.apiResult.NEXT;
    },
  },

  stepContext: {
    BACKGROUND: "background",
    CONTENT: "content",
    PAGE: "page",

    normalize: function (value) {
      value = value ? value.toLowerCase() : undefined;
      if (value === defs.stepContext.BACKGROUND || value === defs.stepContext.PAGE) {
        return value;
      }
      return defs.stepContext.CONTENT;
    },
  },
};

export default defs;
