/*
 When the extension initiates, it reload opened OneLogin tabs to trigger insertion of detectExtension elements and also to initiate oneloginApiServer
 */

import portalClasifier from "../oneloginApiServer/portalPageClassifier.js";
import XBrowserConst from "./const.js";

var tabListeners = {};

function updateUrlWithAuth(originalUrl, username, password) {
  // Create a new URL object from the original URL
  const myURL = new URL(originalUrl);
  if (username && password) {
    // Set the username and password
    myURL.username = username;
    myURL.password = password;
  }

  // Return the updated URL as a string
  return myURL.href;
}

