async function getAllTabs() {
  const tabs = await chrome.tabs.query({});
  return tabs;
}

async function getPortalTabs() {
  const tabs = await getAllTabs();
  return portalClasifier.filterPortalSiteTabs(tabs);
}

/**
 * Get all portal tab in the current window
 */
async function getAllPortalTabs() {
  const tabs = await chrome.tabs.query({ currentWindow: true });
  return portalClasifier.filterAllPortalTabs(tabs);
}

async function getLastTab() {
  const tabs = await getPortalTabs();
  return tabs[tabs.length - 1];
}

async function reload(tab) {
  if (tab) {
    console.log("OneLogin extension initialized, reload last OneLogin admin Windows.");
    await chrome.tabs.reload(tab.id);
  }
}

async function activate(tab) {
  await chrome.tabs.update(tab.id, { active: true });
}

async function getTabInfo(tabHandle) {
  const tab = await chrome.tabs.get(tabHandle);
  return tab;
}

/**
 * params object structure:
 *  {
 *      username?:string,
 *      password?:string,
 *      url:sring
 *  }
 */
async function setTabUrl(tabHandle, params) {
  var authenticationAttempted = false;

  // Hack to support basic authentication
  const data = await chrome.tabs.update(tabHandle, {
    url: updateUrlWithAuth(params.url, params.username, params.password),
  });
  // const data = await chrome.tabs.update(tabHandle, { url: `${params.url}` });
  if (data === null || data === undefined) {
    // in Edge the data parameter is sometimes undefined, the case when it happens is not known
    var lastErrorMsg = "<not set>";

    if (!!chrome.runtime.lastError) {
      // report the error to AirBrake to get more information what happened
      // lastError.message is logged automatically by AirBrake (see airbrake.js)
      lastErrorMsg = chrome.runtime.lastError.message;
      if (!!self.airbrake) {
        self.airbrake.notify(
          new Error(
            `[Debugging info] Callback of tabs.update called with no argument. Update for url: ${
              params.url
            }`
          )
        );
      }
    }
    console.warn(
      `Callback of tabs.update called with no argument. Update for url: ${
        params.url
      } runtime.lastError.message: ${lastErrorMsg}`
    );
  }

  return authenticationAttempted;
}

function clearTabListener(tabId) {
  if (!!tabListeners[tabId]) {
    chrome.tabs.onUpdated.removeListener(tabListeners[tabId].onUpdated);
    chrome.webNavigation.onBeforeNavigate.removeListener(tabListeners[tabId].onBeforeNavigate);
    chrome.webNavigation.onErrorOccurred.removeListener(tabListeners[tabId].onErrorOccurred);

    delete tabListeners[tabId];
  }
}

function setTabListener(tabHandle, listenerFunc) {
  clearTabListener(tabHandle);

  var onUpdated = function (tabId, changeInfo, tab) {
    var mappedTabId = tabHandle;
    if (tabId !== mappedTabId || !changeInfo.status) {
      return;
    }
    var status =
      changeInfo.status === "loading"
        ? XBrowserConst.tabState.LOADING
        : XBrowserConst.tabState.LOADED;
    var info = {
      url: tab.url,
    };
    listenerFunc(mappedTabId, status, info);
  };

  var onBeforeNavigate = function (data) {
    var mappedTabId = tabHandle;
    if (data.tabId === mappedTabId && data.frameId === 0) {
      listenerFunc(mappedTabId, XBrowserConst.tabState.NAVIGATING, {
        url: data.url,
      });
    }
  };

  var onErrorOccurred = function (data) {
    var mappedTabId = tabHandle;
    if (data.tabId === mappedTabId && data.frameId === 0) {
      listenerFunc(mappedTabId, XBrowserConst.tabState.ERROR, {
        url: data.url,
      });
    }
  };

  tabListeners[tabHandle] = {
    onUpdated: onUpdated,
    onBeforeNavigate: onBeforeNavigate,
    onErrorOccurred: onErrorOccurred,
  };

  chrome.tabs.onUpdated.addListener(onUpdated);
  chrome.webNavigation.onBeforeNavigate.addListener(onBeforeNavigate);
  chrome.webNavigation.onErrorOccurred.addListener(onErrorOccurred);
}

export default {
  getLastTab,
  getPortalTabs,
  reload,
  getAllPortalTabs,
  activate,
  getTabInfo,
  setTabUrl,
  clearTabListener,
  setTabListener,
};
