class InMemoryCache {
  constructor() {
    this.cache = {};
  }

  /**
   * All the services/part of the code setting the cache value should use a prefix to define
   * the context of the key to avoid conflicts
   * For eg : for list of apps the key should look like `APPS_LIST`
   */
  set(key, val) {
    this.cache[key] = val;
  }

  get(key) {
    if (this.cache[key]) {
      return this.cache[key];
    }
    return null;
  }

  remove(key) {
    delete this.cache[key];
  }

  invalidateCache() {
    this.cache = {};
  }
}

let inMemoryCache = new InMemoryCache();

export default inMemoryCache;
