import EventEmitter from "eventemitter3";

/* 
    possible navigation events:
            ['userNavigated.webLoginPage', 'userNavigated.portalLogout', 'userNavigated.portalUserSettings', 'userNavigated.portalLoginPage', 'userNavigated.portalMainPage']
 */

/*
from currentUserWebHandler
 In order to provide functionality specific to the user (feature flags and settings) - such as enabled/disabled Logins auto capture,
 the extension needs to know whether user is currently logged in to OneLogin, and the user id and settings.

 The extension listens on calls to the portal/server that may affect change of users state such as login, logout, change of settings.
 On each of such call, the extension re-reads current user info (GET /form-service/me)
 */

/*
from subdomainUrlUpdater
 There are more servers the extension needs to be able to communicate with: production, production-eu, shadow, development. Moreover, each company has its own specific domain. i.e. https://onelogininc.onelogin.com.
 The extension is not explictly connected to specific server, but communicates with last opened portal used by the user.

 Listens on browser calls and once the user opens portal page, store its url into local storage and updates accordingly oneloginApiServer object.
 */

class UserNavigationTracker extends EventEmitter {
  constructor(portalPageClassifier) {
    super();
    this.portalPageClassifier = portalPageClassifier;
  }

  track(url) {
    let eventName = this.getEventName(url);

    if (eventName) {
      console.log("userNavigationTracker emited '%s'", eventName);
      this.emit(eventName, url);
    }
  }

  webHandler(info) {
    if (info.statusCode === 200) {
      this.track(info.url);
    }
  }

  unregisterWebHandler() {
    if (this.handler) {
      chrome.webRequest.onResponseStarted.removeListener(this.handler);
      this.handler = undefined;
    }
  }

  registerWebHandler() {
    console.log("registerWebHandler");
    this.handler = this.webHandler.bind(this);
    chrome.webRequest.onResponseStarted.addListener(this.handler, {
      urls: [
        "*://*/client/settings/*",
        "*://*/profile*",
        "*://*/login*",
        "*://*/client/apps*", //for urls like /client/apps#blabla, Chrome matches without *, but FF needs the * at the end
        //not tracking new portal here as it communicates using postMessages (via CustomEvent)
      ],
    }); // urls just for performance reasons
  }

  // POST /client/settings/{userId} -> 304 -> GET /client/settings nonXHR
  // /logout - nonXHR
  // /sessions - XHR
  // /client/apps - ??

  getEventName(url) {
    //possible navigation events:
    let eventsMap = {
      portalSettingsUrl: "userNavigated.portalUserSettings",
      portalLoginUrl: "userNavigated.portalLoginPage",
      portalSiteListUrl: "userNavigated.portalMainPage",
      legacyPortalSiteListUrl: "userNavigated.portalMainPage",
    };

    return eventsMap[this.portalPageClassifier.classifyPortalUrl(url)];
  }

  logMessageWithABNotify(msg) {
    console.log("MESSAGE : ", msg);
  }
  initWebHandlers() {
    console.log("InitWebHandlers: ");
    var timeoutsToRetry = [0, 100, 200, 300, 500, 800, 1300, 2100]; // increasing set of timeouts for the registration reties
    var retryNr = 0;
    var self = this;
    var doRegistration = function () {
      try {
        console.log("doRegistration");
        self.unregisterWebHandler();
        self.registerWebHandler();
        if (retryNr > 0) {
          self.logMessageWithABNotify(
            "[not error, just info] UserNavigationTracker WebHandler initialized on retry nr: "+
              retryNr
          );
        }
      } catch (err) {
        if (retryNr < timeoutsToRetry.length) {
          if (retryNr == 0) {
            self.logMessageWithABNotify(
              "[not error, just info] UserNavigationTracker WebHandler 1st initialization failed."
            );
          }
          setTimeout(doRegistration, timeoutsToRetry[retryNr++]);
        } else {
          // if (!!self.airbrake) {
          //     self.logMessageWithABNotify(
          //         "UserNavigationTracker WebHandler initialization failed even after "+
          //         retryNr +
          //         "retries."
          //     );
          //     self.airbrake.notify(err);
          // }
        }
      }
    };
    doRegistration();
  }
}

export default UserNavigationTracker;
